from collections import deque
from typing import Dict, List, Optional, TypeVar, Set

# Type variable for nodes/elements in the graph or Union-Find structure
N = TypeVar('N')

def bfs_shortest_path(
    graph: Dict[N, List[N]],
    start_node: N,
    target_node: Optional[N] = None
) -> Optional[List[N]]:
    """
    Performs a Breadth-First Search (BFS) to find the shortest path from a start node
    to a target node in an unweighted graph.

    Args:
        graph: An adjacency list representation of the graph, where keys are nodes
               and values are lists of their neighbors.
        start_node: The node from which to start the BFS.
        target_node: The node to find the shortest path to. If None, the function
                     will traverse the graph from start_node but will return None
                     as no specific target path is requested.

    Returns:
        A list of nodes representing the shortest path from start_node to target_node,
        inclusive. Returns None if the target_node is not reachable or not specified.

    Raises:
        ValueError: If start_node is not in the graph.
    """
    if start_node not in graph:
        raise ValueError(f"Start node '{start_node}' not found in the graph.")

    queue: deque[N] = deque([start_node])
    visited: Set[N] = {start_node}
    predecessors: Dict[N, N] = {} # To reconstruct the path

    while queue:
        current_node = queue.popleft()

        if target_node is not None and current_node == target_node:
            # Reconstruct path
            path: List[N] = []
            node = target_node
            # Walk back from target to start using predecessors
            while node != start_node:
                path.append(node)
                node = predecessors[node]
            path.append(start_node)
            return path[::-1] # Reverse to get path from start to target

        for neighbor in graph.get(current_node, []):
            if neighbor not in visited:
                visited.add(neighbor)
                predecessors[neighbor] = current_node
                queue.append(neighbor)

    return None # Target not reachable or target_node was None

