class UnionFind:
    """
    A Disjoint Set Union (Union-Find) data structure with path compression and
    union by size heuristics.

    It efficiently manages a collection of disjoint sets, allowing for two primary
    operations:
    1.  `find(element)`: Determines the representative (root) of the set containing
        the given element. This operation also performs path compression to flatten
        the tree structure.
    2.  `union(element1, element2)`: Merges the sets containing element1 and element2
        into a single set. This operation uses union by size to keep the trees balanced.

    Elements not present during initialization can be added dynamically when `find`
    or `union` is called on them.
    """
    _parent: Dict[N, N]
    _size: Dict[N, int] # Stores the size of the set rooted at an element

    def __init__(self, elements: Optional[List[N]] = None):
        """
        Initializes the Union-Find structure.
        If a list of elements is provided, each element is initially in its own set.
        Otherwise, it starts empty, and elements are added dynamically.
        """
        self._parent = {}
        self._size = {}
        if elements:
            for e in elements:
                self._parent[e] = e
                self._size[e] = 1

    def _ensure_element_exists(self, element: N) -> None:
        """Helper to add an element to the structure if it doesn't exist."""
        if element not in self._parent:
            self._parent[element] = element
            self._size[element] = 1

    def find(self, element: N) -> N:
        """
        Finds the representative (root) of the set containing the given element.
        Performs path compression for efficiency.

        Args:
            element: The element whose set representative is to be found.

        Returns:
            The representative element of the set.
        """
        self._ensure_element_exists(element)
        if self._parent[element] == element:
            return element
        self._parent[element] = self.find(self._parent[element]) # Path compression
        return self._parent[element]

    def union(self, element1: N, element2: N) -> bool:
        """
        Merges the sets containing element1 and element2.
        Uses union by size heuristic to keep trees balanced.

        Args:
            element1: An element from the first set.
            element2: An element from the second set.

        Returns:
            True if the two elements were in different sets and were successfully
            merged, False otherwise (i.e., they were already in the same set).
        """
        self._ensure_element_exists(element1)
        self._ensure_element_exists(element2)

        root1 = self.find(element1)
        root2 = self.find(element2)

        if root1 != root2:
            # Union by size: attach smaller tree to root of larger tree
            if self._size[root1] < self._size[root2]:
                self._parent[root1] = root2
                self._size[root2] += self._size[root1]
            else:
                self._parent[root2] = root1
                self._size[root1] += self._size[root2]
            return True
        return False # Elements were already in the same set

    def get_num_sets(self) -> int:
        """
        Returns the current number of disjoint sets.
        """
        # Count elements that are their own parent (i.e., roots of sets)
        return sum(1 for e, p in self._parent.items() if e == p)

    def get_set_size(self, element: N) -> int:
        """
        Returns the size of the set containing the given element.
        Finds the root first to ensure path compression and correct size.
        """
        root = self.find(element)
        return self._size[root]

